  const names = new Set(order.items.map((item) => item.name));
  if (names.size >= 3) {
    result *= 0.98;
  }

  if (order.loyaltyMember) {
    result *= 0.95;
  }

  return result;
}

export class PricingFacade {
  private readonly options: ReturnType<typeof resolveOptions>;

  constructor(options?: PricingOptions) {
    this.options = resolveOptions(options);
  }

  price(order: Order): number {
    const hooks = this.options.hooks;
    let total = 0;

    if (hooks.beforeStage) hooks.beforeStage("subtotal");
    for (const item of order.items) {
      total += item.unitPrice * item.quantity;
    }
    if (hooks.afterStage) hooks.afterStage("subtotal", total);

    if (hooks.beforeStage) hooks.beforeStage("discount");
    total = applyDiscount(total, order);
    if (hooks.afterStage) hooks.afterStage("discount", total);

    if (hooks.beforeStage) hooks.beforeStage("tax");
    total *= 1 + this.options.vatRate;
    if (hooks.afterStage) hooks.afterStage("tax", total);

    if (hooks.beforeStage) hooks.beforeStage("rounding");
    total = round(total);
    if (hooks.afterStage) hooks.afterStage("rounding", total);

    return total;
  }
